/* ========================================
   FINAL NAV FIX — light/dark readable
   放在文件最底部，确保覆盖所有前面的规则
   ======================================== */

#nav,
#nav.nav-fixed,
#nav.show {
  background: var(--fu-nav-bg) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid var(--fu-nav-border) !important;
  box-shadow: none !important;
}

#nav.nav-fixed,
#nav.show {
  background: var(--fu-nav-bg-solid) !important;
  box-shadow: var(--fu-nav-shadow) !important;
}

/* 顶级导航文字和图标 */
#nav #site-name,
#nav .site-name,
#nav .site-page,
#nav a,
#nav .menus_items .menus_item > a,
#nav .menus_items .menus_item > span,
#nav .menus_items .menus_item > .site-page {
  color: var(--fu-nav-text) !important;
  text-shadow: none !important;
  opacity: 1 !important;
  transition: color 0.2s ease, background 0.2s ease, text-shadow 0.2s ease;
}

#nav #site-name:hover,
#nav .site-name:hover,
#nav .site-page:hover,
#nav a:hover,
#nav .menus_items .menus_item > a:hover,
#nav .menus_items .menus_item > span:hover,
#nav .menus_items .menus_item > .site-page:hover {
  color: var(--fu-nav-hover) !important;
  text-shadow: 0 0 8px rgba(37, 99, 235, 0.22) !important;
}

/* 防止全局规则把导航图标染成奇怪的灰色 */
#nav .fas,
#nav .fab,
#nav .far,
#nav i {
  color: currentColor !important;
}

/* 下拉菜单 */
#nav .menus_items .menus_item_child {
  background: var(--fu-dropdown-bg) !important;
  backdrop-filter: blur(14px) !important;
  -webkit-backdrop-filter: blur(14px) !important;
  border: 1px solid var(--fu-nav-border) !important;
  border-radius: 12px !important;
  box-shadow: var(--fu-nav-shadow) !important;
  padding: 6px 0 !important;
  overflow: hidden;
}

#nav .menus_items .menus_item_child li,
#nav .menus_items .menus_item_child li a {
  background: transparent !important;
}

#nav .menus_items .menus_item_child li a,
#nav .menus_items .menus_item_child .site-page {
  color: var(--fu-dropdown-text) !important;
  text-shadow: none !important;
  opacity: 1 !important;
}

#nav .menus_items .menus_item_child li a:hover,
#nav .menus_items .menus_item_child .site-page:hover {
  color: var(--fu-dropdown-hover-text) !important;
  background: var(--fu-dropdown-hover-bg) !important;
  text-shadow: 0 0 8px rgba(37, 99, 235, 0.2) !important;
}

/* 深色模式下拉 hover 用浅色 shadow */
[data-theme="dark"] #nav a:hover,
[data-theme="dark"] #nav .menus_items .menus_item > a:hover,
[data-theme="dark"] #nav .menus_items .menus_item > span:hover {
  text-shadow: 0 0 8px rgba(147, 197, 253, 0.3) !important;
}

[data-theme="dark"] #nav .menus_items .menus_item_child li a:hover {
  text-shadow: 0 0 8px rgba(147, 197, 253, 0.28) !important;
}

/* 移动端侧边菜单 — 高级极简玻璃质感 */
#sidebar #menu-mask {
  transition: opacity 0.35s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
}

#sidebar #sidebar-menus {
  background: rgba(255, 255, 255, 0.94) !important;
  backdrop-filter: blur(20px) saturate(1.4) !important;
  -webkit-backdrop-filter: blur(20px) saturate(1.4) !important;
  border-left: 1px solid rgba(255, 255, 255, 0.6) !important;
  box-shadow: -8px 0 40px rgba(0, 0, 0, 0.08) !important;
  padding-top: 60px !important;
  padding-bottom: 40px !important;
  width: 280px !important;
  right: -280px !important;
  transition: transform 0.38s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
}

#sidebar #sidebar-menus.open {
  transform: translate3d(-100%, 0, 0) !important;
}

/* 菜单分组容器 — 透明无背景 */
#sidebar #sidebar-menus .menus_items {
  margin: 0 20px !important;
  padding: 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  border-radius: 0 !important;
}

/* 顶级菜单项 */
#sidebar #sidebar-menus .menus_items .site-page {
  display: flex !important;
  align-items: center !important;
  margin: 2px 0 !important;
  padding: 12px 16px !important;
  color: #1f2937 !important;
  font-size: 1rem !important;
  font-weight: 500 !important;
  letter-spacing: 0.02em;
  border-radius: 10px !important;
  transition: all 0.2s ease !important;
  cursor: pointer !important;
}

#sidebar #sidebar-menus .menus_items .site-page:hover {
  background: rgba(37, 99, 235, 0.06) !important;
  color: #2563eb !important;
}

#sidebar #sidebar-menus .menus_items .site-page i:first-child {
  width: 24px !important;
  margin-right: 10px !important;
  font-size: 1.05rem !important;
  text-align: center !important;
  opacity: 0.7;
}

/* 分组标题（有子菜单的项） */
#sidebar #sidebar-menus .menus_items .site-page.group {
  justify-content: space-between !important;
  font-weight: 600 !important;
}

#sidebar #sidebar-menus .menus_items .site-page.group > i:last-child {
  font-size: 0.7rem !important;
  opacity: 0.5;
  transition: transform 0.3s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
}

#sidebar #sidebar-menus .menus_items .site-page.group:not(.hide) > i:last-child {
  transform: rotate(180deg) !important;
  opacity: 0.8;
}

/* 子菜单容器 — 平滑展开 */
#sidebar #sidebar-menus .menus_items .menus_item_child {
  max-height: 0 !important;
  opacity: 0 !important;
  overflow: hidden !important;
  margin: 0 0 0 12px !important;
  padding: 0 !important;
  border-left: 1px solid rgba(148, 163, 184, 0.2) !important;
  transition: max-height 0.35s cubic-bezier(0.25, 0.8, 0.25, 1), opacity 0.25s ease !important;
}

#sidebar #sidebar-menus .site-page.group:not(.hide) + .menus_item_child {
  max-height: 600px !important;
  opacity: 1 !important;
}

/* 子菜单项 */
#sidebar #sidebar-menus .menus_item_child li a,
#sidebar #sidebar-menus .menus_item_child .site-page {
  display: flex !important;
  align-items: center !important;
  padding: 10px 14px !important;
  color: #4b5563 !important;
  font-size: 0.93rem !important;
  font-weight: 400 !important;
  border-radius: 8px !important;
  transition: all 0.2s ease !important;
}

#sidebar #sidebar-menus .menus_item_child li a:hover,
#sidebar #sidebar-menus .menus_item_child .site-page:hover {
  color: #2563eb !important;
  background: rgba(37, 99, 235, 0.06) !important;
}

#sidebar #sidebar-menus .menus_item_child li a i:first-child,
#sidebar #sidebar-menus .menus_item_child .site-page i:first-child {
  width: 20px !important;
  margin-right: 8px !important;
  font-size: 0.9rem !important;
  opacity: 0.6;
}

/* ========================================
   FINAL NAV DROPDOWN FIX
   修复二级菜单 hover 断层 + 隐藏三角箭头
   ======================================== */

/* 关键：page-header 需要 overflow: visible 否则裁剪下拉菜单 */
#page-header {
  overflow: visible !important;
}

/* 导航层稳定 */
#nav {
  z-index: 9998 !important;
  overflow: visible !important;
}

#nav .menus_items {
  overflow: visible !important;
}

#nav .menus_items .menus_item {
  position: relative !important;
  overflow: visible !important;
}

/* 顶级导航格式统一，去掉多余间距 */
#nav .menus_items .menus_item > a,
#nav .menus_items .menus_item > span,
#nav .menus_items .menus_item > .site-page {
  display: inline-flex !important;
  align-items: center !important;
  gap: 0 !important;
  padding: 0 0.72rem !important;
  white-space: nowrap !important;
}

/* 下拉菜单：opacity + visibility + pointer-events 替代 display:none，避免 hover 瞬断 */
#nav .menus_items .menus_item_child {
  display: block !important;
  position: absolute !important;
  top: calc(100% - 2px) !important;
  left: 50% !important;
  min-width: 136px !important;
  margin: 0 !important;
  padding: 6px 0 !important;
  transform: translateX(-50%) translateY(6px) !important;
  opacity: 0 !important;
  visibility: hidden !important;
  pointer-events: none !important;
  z-index: 10000 !important;
  transition: opacity 0.16s ease, visibility 0.16s ease, transform 0.16s ease !important;
}

/* 透明 hover 桥：填补父菜单和下拉菜单之间的间隙 */
#nav .menus_items .menus_item_child::before {
  content: "" !important;
  position: absolute !important;
  left: 0 !important;
  right: 0 !important;
  top: -14px !important;
  height: 14px !important;
  background: transparent !important;
  pointer-events: auto !important;
}

/* 三层 hover 联动：父菜单或子菜单被 hover 时都保持显示 */
#nav .menus_items .menus_item:hover > .menus_item_child,
#nav .menus_items .menus_item:focus-within > .menus_item_child,
#nav .menus_items .menus_item_child:hover {
  opacity: 1 !important;
  visibility: visible !important;
  pointer-events: auto !important;
  transform: translateX(-50%) translateY(0) !important;
}

/* 子菜单链接确保可点击 */
#nav .menus_items .menus_item_child li {
  display: block !important;
  position: relative !important;
  z-index: 10001 !important;
  margin: 0 !important;
  padding: 0 !important;
}

#nav .menus_items .menus_item_child li a,
#nav .menus_items .menus_item_child .site-page {
  display: flex !important;
  align-items: center !important;
  width: 100% !important;
  min-height: 34px !important;
  padding: 0.48rem 0.9rem !important;
  line-height: 1.4 !important;
  white-space: nowrap !important;
  cursor: pointer !important;
  pointer-events: auto !important;
}

/* 隐藏下拉三角 / 箭头 */
#nav .menus_items .menus_item > a .fa-chevron-down,
#nav .menus_items .menus_item > span .fa-chevron-down,
#nav .menus_items .menus_item > .site-page .fa-chevron-down,
#nav .menus_items .menus_item > a .fa-angle-down,
#nav .menus_items .menus_item > span .fa-angle-down,
#nav .menus_items .menus_item > .site-page .fa-angle-down,
#nav .menus_items .menus_item > a .fa-caret-down,
#nav .menus_items .menus_item > span .fa-caret-down,
#nav .menus_items .menus_item > .site-page .fa-caret-down {
  display: none !important;
}

/* 禁用伪元素三角 */
#nav .menus_items .menus_item > a::after,
#nav .menus_items .menus_item > span::after,
#nav .menus_items .menus_item > .site-page::after {
  display: none !important;
  content: none !important;
}

/* 禁止箭头旋转动画 */
#nav .menus_items .menus_item i {
  transform: none !important;
  animation: none !important;
  transition: none !important;
}

/* 导航图标跟随文字颜色 */
#nav .fas,
#nav .far,
#nav .fab,
#nav i {
  color: currentColor !important;
}

/* 下拉菜单颜色使用变量 */
#nav .menus_items .menus_item_child {
  background: var(--fu-dropdown-bg) !important;
  border: 1px solid var(--fu-nav-border) !important;
  border-radius: 12px !important;
  box-shadow: var(--fu-nav-shadow) !important;
  backdrop-filter: blur(14px) !important;
  -webkit-backdrop-filter: blur(14px) !important;
}

#nav .menus_items .menus_item_child li a,
#nav .menus_items .menus_item_child .site-page {
  color: var(--fu-dropdown-text) !important;
  background: transparent !important;
  text-shadow: none !important;
}

#nav .menus_items .menus_item_child li a:hover,
#nav .menus_items .menus_item_child .site-page:hover {
  color: var(--fu-dropdown-hover-text) !important;
  background: var(--fu-dropdown-hover-bg) !important;
}

/* 移动端不使用桌面 hover 逻辑 */
@media screen and (max-width: 768px) {
  #nav .menus_items .menus_item_child {
    position: static !important;
    transform: none !important;
    opacity: 1 !important;
    visibility: visible !important;
    pointer-events: auto !important;
    box-shadow: none !important;
    border-radius: 0 !important;
  }

  #nav .menus_items .menus_item_child::before {
    display: none !important;
  }
}

