/* ========================================
   世界线记录 — Steins;Gate 归档页面
   ======================================== */

.wl-hero {
  text-align: center;
  padding: 2.5rem 1.5rem 1.5rem;
  position: relative;
}

.wl-divergence-meter {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  position: relative;
  background: #020617;
  border: 1px solid #3d1a0c;
  border-radius: 8px;
  padding: 8px 20px;
  margin-bottom: 20px;
  font-family: 'Courier New', Courier, monospace;
  box-shadow: 0 0 10px rgba(245, 158, 11, 0.12), inset 0 0 4px rgba(245, 158, 11, 0.04);
  animation: wl-meter-glow 5s ease-in-out infinite;
  overflow: hidden;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}

/* 边框发光扫过 — 仿 nixie 管灯丝通电 */
.wl-divergence-meter::before {
  content: '';
  position: absolute;
  inset: -3px;
  border-radius: 10px;
  background: conic-gradient(
    transparent 40%,
    rgba(245, 158, 11, 0.25) 48%,
    rgba(234, 88, 12, 0.4) 50%,
    rgba(220, 38, 38, 0.25) 52%,
    transparent 60%
  );
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  animation: wl-border-sweep 8s linear infinite;
  z-index: 0;
  pointer-events: none;
}

@keyframes wl-border-sweep {
  0%   { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* CRT 扫描线 */
.wl-divergence-meter::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(0, 0, 0, 0.03) 2px,
    rgba(0, 0, 0, 0.03) 4px
  );
  border-radius: 8px;
  z-index: 0;
  pointer-events: none;
}

.wl-meter-label {
  position: relative;
  z-index: 1;
  color: #64748b;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.wl-meter-value {
  position: relative;
  z-index: 1;
  color: #f59e0b;
  font-size: 1.6rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-shadow: 0 0 8px rgba(245, 158, 11, 0.5), 0 0 20px rgba(245, 158, 11, 0.2);
  animation: wl-meter-breathe 4s ease-in-out infinite;
}

.wl-counter {
  animation: wl-counter-flicker 5s ease-in-out infinite;
}

/* 外发光呼吸 */
@keyframes wl-meter-glow {
  0%, 100% {
    box-shadow: 0 0 10px rgba(245, 158, 11, 0.12), inset 0 0 4px rgba(245, 158, 11, 0.04);
    border-color: #3d1a0c;
  }
  33% {
    box-shadow: 0 0 16px rgba(234, 88, 12, 0.18), inset 0 0 7px rgba(234, 88, 12, 0.06);
    border-color: #4a2010;
  }
  66% {
    box-shadow: 0 0 13px rgba(220, 38, 38, 0.14), inset 0 0 5px rgba(220, 38, 38, 0.05);
    border-color: #3d1808;
  }
}


/* 文字呼吸 */
@keyframes wl-meter-breathe {
  0%, 100% {
    text-shadow: 0 0 6px rgba(245, 158, 11, 0.35), 0 0 14px rgba(245, 158, 11, 0.14);
  }
  50% {
    text-shadow: 0 0 9px rgba(234, 88, 12, 0.45), 0 0 20px rgba(234, 88, 12, 0.2);
  }
}

/* 数字闪烁 — 柔和 */
@keyframes wl-counter-flicker {
  0%, 100% { opacity: 1; }
  93% { opacity: 1; }
  94% { opacity: 0.8; }
  95% { opacity: 0.95; }
  96% { opacity: 0.72; }
  97% { opacity: 0.9; }
  98% { opacity: 0.78; }
  99% { opacity: 1; }
}

