/* ========================================
   NAV PAGE TITLE FIX
   "返回首页" 始终在左侧，文章标题居中显示
   ======================================== */

/* 父容器回归 static，使子元素可相对 #nav 定位
   不强制 display，由主题 JS 控制显示/隐藏 */
#nav .nav-page-title {
  position: static !important;
}

/* "返回首页" — 正常文档流，左侧显示 */
#nav .nav-page-title > :last-child {
  position: static !important;
  opacity: 1 !important;
  transform: none !important;
  white-space: nowrap !important;
}

/* 文章标题 — 相对导航栏绝对居中 */
#nav .nav-page-title > :first-child {
  position: absolute !important;
  left: 50% !important;
  top: 50% !important;
  transform: translate(-50%, -50%) !important;
  max-width: 36vw !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;
  white-space: nowrap !important;
  pointer-events: none !important;
}

/* 取消 hover 动画，保持居中不动 */
#nav .nav-page-title:hover > :first-child {
  opacity: 1 !important;
  transform: translate(-50%, -50%) !important;
}

/* 移动端：屏幕窄小，导航栏只保留返回首页按钮 */
@media screen and (max-width: 900px) {
  /* 彻底隐藏文章标题 */
  #nav .nav-page-title > :first-child {
    display: none !important;
  }

  /* 返回首页字号适配 */
  #nav .nav-page-title > :last-child {
    font-size: 0.85em !important;
  }

  /* nav-fixed 状态下强制只显示返回首页，隐藏博客名 */
  #page-header.nav-fixed #nav #blog-info > a:first-child {
    display: none !important;
  }

  #page-header.nav-fixed #nav #blog-info > a:last-child {
    display: block !important;
  }

  /* blog-info 保持 flex:1 撑开左侧，文字溢出截断 */
  #nav #blog-info {
    flex: 1 !important;
    overflow: hidden !important;
    text-overflow: ellipsis !important;
    white-space: nowrap !important;
  }

  /* menus 用 margin-left: auto 强制推到最右侧 */
  #nav #menus {
    margin-left: auto !important;
    display: flex !important;
    align-items: center !important;
    flex-shrink: 0 !important;
  }

  /* 搜索按钮可见，在菜单按钮左侧 */
  #nav #search-button {
    display: inline !important;
    padding: 0 8px !important;
  }
}

