  color: #ffffff !important;
  background: #6366f1 !important;
  box-shadow: 0 4px 16px rgba(99, 102, 241, 0.35) !important;
  transform: translateY(-2px) scale(1.04) !important;
}

/* --- 侧边栏标签云 --- */
.card-tag-cloud a {
  display: inline-block !important;
  margin: 3px 4px !important;
  padding: 3px 10px !important;
  border: 1px solid rgba(99, 102, 241, 0.25) !important;
  border-radius: 6px !important;
  color: #4f46e5 !important;
  font-size: 0.88em !important;
  font-weight: 500 !important;
  text-decoration: none !important;
  transition: all 0.2s ease !important;
}

.card-tag-cloud a:hover {
  background: #6366f1 !important;
  color: #ffffff !important;
  border-color: #6366f1 !important;
}

/* --- 深色模式 --- */
[data-theme="dark"] .tag-cloud-list a {
  text-shadow: 0 1px 3px rgba(0, 0, 0, 0.4) !important;
}

[data-theme="dark"] .card-tag-cloud a {
  color: #a5b4fc !important;
  border-color: rgba(165, 180, 252, 0.3) !important;
}

[data-theme="dark"] .card-tag-cloud a:hover {
  background: #818cf8 !important;
  color: #ffffff !important;
  border-color: #818cf8 !important;
}

/* --- 移动端适配 --- */
@media screen and (max-width: 900px) {
  .tag-cloud-list a {
    padding: 6px 14px !important;
    margin: 4px !important;
    font-size: 0.95em !important;
  }

  .card-tag-cloud a {
    padding: 4px 10px !important;
    margin: 3px !important;
    font-size: 0.85em !important;
  }
}

/* ========================================
   POST BOTTOM TAGS OPTIMIZATION
   文章底部标签 + 分享按钮，PC/移动端统一整洁
   ======================================== */

/* --- 标签容器 --- */
#post .tag_share {
  display: flex !important;
  flex-wrap: wrap !important;
  align-items: center !important;
  justify-content: space-between !important;
  gap: 10px !important;
  margin-top: 30px !important;
  padding-top: 20px !important;
  border-top: 1px solid rgba(0, 0, 0, 0.08) !important;
}

/* --- 单个标签 --- */
#post .tag_share .post-meta__tags {
  display: inline-flex !important;
  align-items: center !important;
  margin: 0 !important;
  padding: 5px 14px !important;
  border: 1px solid #b8a6d9 !important;
  border-radius: 20px !important;
  background: rgba(184, 166, 217, 0.06) !important;
  color: #7c6aa0 !important;
  font-size: 0.85em !important;
  font-weight: 500 !important;
  text-decoration: none !important;
  transition: all 0.25s ease !important;
}

#post .tag_share .post-meta__tags:hover {
  background: #b8a6d9 !important;
  color: #ffffff !important;
  border-color: #b8a6d9 !important;
  transform: translateY(-1px) !important;
  box-shadow: 0 3px 12px rgba(184, 166, 217, 0.3) !important;
}

/* --- 标签列表容器 --- */
#post .tag_share .post-meta__tag-list {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

/* --- 分享按钮区域 --- */
#post .tag_share .post-share {
  float: none !important;
  margin: 0 !important;
  flex-shrink: 0 !important;
}

#post .tag_share .post-share .social-share .social-share-icon {
  border-radius: 50% !important;
  transition: all 0.2s ease !important;
}

/* --- 深色模式 --- */
[data-theme="dark"] #post .tag_share {
  border-top-color: rgba(255, 255, 255, 0.08) !important;
}

[data-theme="dark"] #post .tag_share .post-meta__tags {
  border-color: rgba(184, 166, 217, 0.35) !important;
  background: rgba(184, 166, 217, 0.1) !important;
  color: #c4b5e0 !important;
}

[data-theme="dark"] #post .tag_share .post-meta__tags:hover {
  background: #b8a6d9 !important;
  color: #1a1a2e !important;
}

/* --- 移动端：标签和分享按钮各占一行 --- */
@media screen and (max-width: 900px) {
  #post .tag_share {
    flex-direction: column !important;
    align-items: flex-start !important;
    gap: 14px !important;
  }

  #post .tag_share .post-meta__tag-list {
    width: 100% !important;
  }

  #post .tag_share .post-meta__tags {
    padding: 6px 16px !important;
    font-size: 0.88em !important;
  }

  #post .tag_share .post-share {
    align-self: flex-end !important;
  }
}

/* ===== Steins;Gate Style Typing Effect (High Contrast) ===== */
#subtitle {
  font-family: 'JetBrains Mono', 'Fira Code', 'IBM Plex Mono',
               'Noto Serif SC', 'Source Han Serif SC', 'Songti SC',
               serif, monospace;
  font-weight: 600;
  letter-spacing: 0.06em;
  color: #FFA04D !important;
  text-shadow:
    0 0 1px #FFD4A3,
    0 0 3px rgba(255, 160, 77, 0.9),
    0 0 8px rgba(255, 106, 26, 0.4),
    0 0 16px rgba(255, 59, 0, 0.2);
  transition: text-shadow 0.3s ease;
}

#subtitle .typed-cursor {
  color: #FFA04D !important;
  font-weight: 500;
  text-shadow:
    0 0 1px #FFD4A3,
    0 0 3px rgba(255, 160, 77, 0.9),
    0 0 8px rgba(255, 106, 26, 0.35);
}

/* ===== 移动端 Steins;Gate 风格适配 ===== */

/* 1. 移动端 subtitle 打字效果优化 */
@media screen and (max-width: 768px) {
  #subtitle {
    font-size: 1.05rem !important;
    font-weight: 600 !important;
    letter-spacing: 0.05em !important;
    color: #FFA04D !important;
    text-shadow:
      0 0 1px #FFD4A3,
      0 0 4px rgba(255, 160, 77, 0.95),
      0 0 10px rgba(255, 106, 26, 0.5),
      0 0 18px rgba(255, 59, 0, 0.25) !important;
    line-height: 1.6 !important;
  }

  #subtitle .typed-cursor {
    color: #FFA04D !important;
    text-shadow:
      0 0 1px #FFD4A3,
      0 0 4px rgba(255, 160, 77, 0.95) !important;
  }

  /* site-name 主标题也增强一下，保持视觉统一 */
  #site-name,
  #site_social_icons {
    text-shadow: 0 0 8px rgba(255, 106, 26, 0.3);
  }
}

/* 2. 移动端侧边栏 widget（世界线记录、博主日常、分类、标签等）配色统一 */
@media screen and (max-width: 768px) {
  #aside-content .card-widget {
    background: rgba(20, 15, 12, 0.55) !important;
    border: 1px solid rgba(255, 106, 26, 0.18);
    border-radius: 8px;
    backdrop-filter: blur(6px);
    -webkit-backdrop-filter: blur(6px);
  }

  /* widget 标题（"世界线记录""分类""标签"等） */
  #aside-content .item-headline,
  #aside-content .card-widget .item-headline span {
    color: #FFA04D !important;
    font-weight: 600;
    letter-spacing: 0.04em;
    text-shadow: 0 0 4px rgba(255, 106, 26, 0.4);
  }

  /* widget 内的链接文字（归档月份、分类名、标签名等） */
  #aside-content .card-widget a,
  #aside-content .aside-list-item a,
  #aside-content .card-archives a,
  #aside-content .card-categories a {
    color: rgba(255, 200, 150, 0.92) !important;
    transition: all 0.25s ease;
  }

  #aside-content .card-widget a:hover {
    color: #FFA04D !important;
    text-shadow: 0 0 6px rgba(255, 106, 26, 0.6);
  }

  /* 数字角标（文章数量等） */
  #aside-content .length-num {
    color: #FF7A2A !important;
    font-weight: 600;
  }

  /* 标签云在移动端的可读性 */
  #aside-content .card-tags .card-tag-cloud a {
    color: rgba(255, 200, 150, 0.85) !important;
    font-size: 0.95em !important;
  }
}

/* 3. 移动端文章卡片标题轻微增强（可选氛围） */
@media screen and (max-width: 768px) {
  #recent-posts .recent-post-item .article-title {
    transition: all 0.3s ease;
  }
  #recent-posts .recent-post-item .article-title:hover {
    color: #FFA04D !important;
    text-shadow: 0 0 6px rgba(255, 106, 26, 0.4);
  }
}

/* 4. 修复 Butterfly 主题在某些机型上 subtitle 被隐藏的问题 */
@media screen and (max-width: 768px) {
  #site-info #site-title,
  #site-info #site-subtitle,
  #site-info #subtitle {
    display: block !important;
    visibility: visible !important;
    opacity: 1 !important;
  }
}
